    stripeAchCustomerId: '',
    achExpectedDebitDate: '',
    achFailureCode: '',
    achFailureMessage: '',
    achPendingProductionApprovedAtOrder: '',
    stripeLatestChargeId: '',
    stripeLatestEventId: '',
    stripeLatestEventType: '',
    stripeLatestEventAt: '',
    invoiceNumber: '',
